<style>
:root{--page-bg:#f3f4f6;--card-bg:#ffffff;--text-main:#111827;--text-muted:#6b7280;--input-bg:#f9fafb;--input-border:#e5e7eb;--accent:#2563eb;--accent-hover:#1d4ed8;--social-border:#e5e7eb}html.dark{--page-bg:#0f172a;--card-bg:#1e293b;--text-main:#f8fafc;--text-muted:#94a3b8;--input-bg:#0f172a;--input-border:#334155;--accent:#3b82f6;--accent-hover:#60a5fa;--social-border:#334155}body{margin:0;min-height:100vh;display:flex;align-items:center;justify-content:center;font-family:Inter,system-ui,-apple-system,sans-serif;background-color:var(--page-bg);color:var(--text-main);transition:background .3s ease}.login-card{background:var(--card-bg);padding:2.5rem;border-radius:1.5rem;box-shadow:0 20px 25px -5px rgba(0,0,0,.1),0 10px 10px -5px rgba(0,0,0,.04);width:100%;max-width:420px;border:1px solid var(--social-border)}h1{font-size:1.875rem;font-weight:700;margin:0 0 .5rem;text-align:center}.select-provider{text-align:center;color:var(--text-muted);font-size:.875rem;margin-bottom:2rem}.auth-tabs{display:flex;background:var(--input-bg);padding:4px;border-radius:.75rem;margin-bottom:1.5rem;border:1px solid var(--input-border)}.tab-button{flex:1;padding:.625rem;border:none;background:0 0;cursor:pointer;font-weight:600;color:var(--text-muted);border-radius:.5rem;transition:all .2s;font-size:.875rem}.tab-button.active{background:var(--card-bg);color:var(--text-main);box-shadow:0 4px 6px -1px rgba(0,0,0,.1)}.field-group{margin-bottom:1.25rem}.field-group label{display:block;margin-bottom:.5rem;font-size:.75rem;font-weight:600;text-transform:uppercase;letter-spacing:.05em;color:var(--text-muted)}.input-style{width:100%;padding:.75rem 1rem;border-radius:.625rem;border:1px solid var(--input-border);background:var(--input-bg);color:var(--text-main);font-size:1rem;transition:border-color .2s,box-shadow .2s;box-sizing:border-box}.input-style:focus{outline:0;border-color:var(--accent);box-shadow:0 0 0 3px rgba(37,99,235,.1)}.name-grid{display:grid;grid-template-columns:1fr 1fr;gap:1rem;margin-bottom:1.25rem}.submit-btn{width:100%;padding:.875rem;background:var(--accent);color:#fff;border:none;border-radius:.625rem;font-weight:600;font-size:1rem;cursor:pointer;transition:background .2s;margin-top:.5rem}.submit-btn:hover{background:var(--accent-hover)}.separator{display:flex;align-items:center;margin:1.5rem 0;color:var(--text-muted);font-size:.75rem;text-transform:uppercase;letter-spacing:.1em}.separator::after,.separator::before{content:"";flex:1;height:1px;background:var(--input-border)}.separator:not(:empty)::before{margin-right:1rem}.separator:not(:empty)::after{margin-left:1rem}.social-grid{display:flex;flex-direction:column;gap:.75rem}.social-btn{display:flex;align-items:center;justify-content:center;gap:.75rem;padding:.75rem;border:1px solid var(--social-border);border-radius:.625rem;background:var(--card-bg);color:var(--text-main);text-decoration:none;font-weight:500;font-size:.875rem;transition:background .2s}.social-btn:hover{background:var(--input-bg)}.social-btn svg{width:20px;height:20px}.social-btn svg.apple-logo{color:#000}.dark .social-btn svg.apple-logo{color:#fff}.back-link{display:block;text-align:center;margin-top:1.5rem;color:var(--text-muted);text-decoration:none;font-size:.875rem;transition:color .2s}.back-link:hover{color:var(--text-main);text-decoration:underline}.alert{padding:1rem;border-radius:.625rem;margin-bottom:1.5rem;font-size:.875rem;border:1px solid transparent}.alert-error{background-color:#fee2e2;color:#991b1b;border-color:#fecaca}.dark .alert-error{background-color:#450a0a;color:#fecaca;border-color:#7f1d1d}.alert-success{background-color:#dcfce7;color:#166534;border-color:#bbf7d0}.dark .alert-success{background-color:#064e3b;color:#bbf7d0;border-color:#065f46}.error-detail{margin-top:.25rem;font-size:.75rem;opacity:.8}.error-msg{color:#ef4444;font-size:.75rem;margin-top:.25rem}.dark .error-msg{color:#f87171}.registration-success{text-align:center;padding:2rem 1rem;background:var(--input-bg);border-radius:1rem;border:1px dashed var(--accent)}.success-icon{font-size:3rem;color:var(--accent);margin-bottom:1rem}.registration-success p{color:var(--text-main);font-weight:500;margin:0}
</style>